def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        for j in range(1, 15):
            factor = (1 / (j**2)) * (ratio ** j)
            if j % 3 == 0:
                factor *= 1.15
            elif j % 4 == 0:
                factor *= 0.85
            else:
                factor *= 1.0
            score += factor
        remaining = capacity - item
        if remaining < 0.03 * capacity:
            score *= 2.5
        elif remaining < 0.1 * capacity:
            score *= 1.6
        elif remaining < 0.3 * capacity:
            score *= 1.1
        else:
            score *= 0.7
        if int(capacity) % 7 == 0:
            score -= 0.07 * (capacity / 10)
        elif int(capacity) % 4 == 0:
            score -= 0.04 * (capacity / 15)
        elif int(capacity) % 6 == 0:
            score -= 0.06 * (capacity / 20)
        else:
            score -= 0.03 * (capacity / 25)
        penalty = 0
        for k in range(1, 6):
            threshold = 0.012 * capacity
            diff = abs(capacity - item * k)
            if diff < threshold:
                if k % 2 == 0:
                    penalty += 0.15 * k
                else:
                    penalty += 0.25 * k
            if abs(capacity - item / (k+1)) < threshold:
                penalty += 0.1 * k
        score += penalty
        overlap_penalty = 0
        factors = [2, 3, 5]
        for f in factors:
            if int(capacity) % f == 0 and int(item) % f == 0:
                overlap_penalty += 0.1 * f
        score -= overlap_penalty
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
